sql:
SELECT title, creation_date
FROM media_records
WHERE status = 'published';

SELECT media_id, COUNT(distribution_id) AS distribution_count
FROM media_distribution
GROUP BY media_id;

SELECT distribution_date, quantity, status
FROM media_distribution
WHERE status = 'completed';

SELECT media_type_id, COUNT(*) AS media_count
FROM media_records
GROUP BY media_type_id;

SELECT COUNT(DISTINCT media_id) AS total_media_accessed
FROM media_access
WHERE access_date >= '1904-01-10';

SELECT COUNT(*) 
FROM media_distribution 
WHERE media_id = 1 AND status = 'completed';

